if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const body = $('Auth Guard').first().json;
const action = (body.action || 'list').toLowerCase();
let query = '';
let meta = { action };

switch (action) {
  case 'upsert':
  case 'create':
    const esc = s => (s || '').replace(/'/g, "''");
    query = `INSERT INTO gda_contacts (govtribe_id, name, email, phone, title, role, organization, agency, dept, notes, source, last_interaction, updated_at)
      VALUES ('${esc(body.govtribe_id)}', '${esc(body.name)}', '${esc(body.email)}', '${esc(body.phone)}', '${esc(body.title)}', '${esc(body.role)}', '${esc(body.organization)}', '${esc(body.agency)}', '${esc(body.dept)}', '${esc(body.notes)}', '${esc(body.source || 'Manual')}', NOW(), NOW())
      ON CONFLICT (govtribe_id) DO UPDATE SET
        name = EXCLUDED.name,
        email = COALESCE(NULLIF(EXCLUDED.email,''), gda_contacts.email),
        phone = COALESCE(NULLIF(EXCLUDED.phone,''), gda_contacts.phone),
        title = COALESCE(NULLIF(EXCLUDED.title,''), gda_contacts.title),
        role = COALESCE(NULLIF(EXCLUDED.role,''), gda_contacts.role),
        organization = COALESCE(NULLIF(EXCLUDED.organization,''), gda_contacts.organization),
        updated_at = NOW()
      RETURNING *;`;
    meta.action = 'upsert';
    break;
  case 'delete':
    query = `DELETE FROM gda_contacts WHERE id = ${parseInt(body.id) || 0} RETURNING id, name;`;
    break;
  case 'search':
    const q = (body.q || '').replace(/'/g, "''");
    query = `SELECT * FROM gda_contacts WHERE name ILIKE '%${q}%' OR organization ILIKE '%${q}%' OR agency ILIKE '%${q}%' OR email ILIKE '%${q}%' ORDER BY updated_at DESC LIMIT 25;`;
    break;
  case 'get':
    query = `SELECT * FROM gda_contacts WHERE id = ${parseInt(body.id) || 0};`;
    break;
  default: // list
    const limit = parseInt(body.limit) || 50;
    const offset = parseInt(body.offset) || 0;
    const dept = body.dept ? `WHERE dept ILIKE '%${(body.dept || '').replace(/'/g, "''")}%'` : '';
    query = `SELECT * FROM gda_contacts ${dept} ORDER BY updated_at DESC LIMIT ${limit} OFFSET ${offset};`;
    meta.action = 'list';
}
return [{ json: { query, meta } }];

const meta = $('Build Query').first().json.meta;
const rows = $input.all().map(i => i.json).filter(r => r.id !== undefined);
const resp = { status: 'ok', action: meta.action };
if (meta.action === 'upsert' || meta.action === 'create' || meta.action === 'get') {
  resp.contact = rows[0] || null;
} else if (meta.action === 'delete') {
  resp.deleted = rows[0] || null;
} else {
  resp.contacts = rows;
  resp.count = rows.length;
}
resp.timestamp = new Date().toISOString();
return [{ json: resp }];
